// ===== SLS (Satuan Lingkungan Setempat) — fitur tambahan =====
let slsDB=JSON.parse(localStorage.getItem("se2026_slsDB")||"[]");
function persistSlsDB(){localStorage.setItem("se2026_slsDB",JSON.stringify(slsDB)),jadwalkanSyncData()}
function namaSlsById(id){const s=slsDB.find(x=>x.id===id);return s?s.nama:""}
function renderDaftarSLS(){
  const el=document.getElementById("daftarSlsList");
  if(!el)return;
  if(!slsDB.length){el.innerHTML='<div class="hint" style="padding:8px 0">Belum ada SLS. Tambahkan di atas.</div>';return}
  el.innerHTML=slsDB.map(s=>`<div class="sls-row" style="display:flex;align-items:center;justify-content:space-between;padding:8px 0;border-bottom:1px solid #eee"><span>${s.nama}</span><button onclick='hapusSLS("${s.id}")' style="background:#fee;color:#c00;border:1px solid #c00;border-radius:6px;padding:4px 10px;cursor:pointer;font-size:12px">🗑️ Hapus</button></div>`).join("")
}
function renderDropdownSLS(){
  const opts='<option value="">— Pilih SLS —</option>'+slsDB.map(s=>`<option value="${s.id}">${s.nama}</option>`).join("");
  const sel1=document.getElementById("slsResponden");
  if(sel1){const cur=sel1.value;sel1.innerHTML=opts;sel1.value=cur}
  const selFilter=document.getElementById("filterSLS");
  if(selFilter){const cur=selFilter.value;selFilter.innerHTML='<option value="">Semua SLS</option>'+slsDB.map(s=>`<option value="${s.id}">${s.nama}</option>`).join("");selFilter.value=cur}
}
function tambahSLS(){
  const input=document.getElementById("inputSlsBaru");
  const nama=(input&&input.value||"").trim();
  if(!nama)return void showToast("⚠️ Nama SLS kosong");
  if(slsDB.some(s=>s.nama.toLowerCase()===nama.toLowerCase()))return void showToast("⚠️ SLS sudah ada di daftar");
  slsDB.push({id:"sls_"+Date.now(),nama});
  persistSlsDB();
  if(input)input.value="";
  renderDaftarSLS();
  renderDropdownSLS();
  showToast("✅ SLS ditambahkan")
}
function hapusSLS(id){
  if(!confirm("Hapus SLS ini dari daftar?\n(Data responden yang sudah memakai SLS ini tetap tersimpan, hanya nama SLS-nya tidak lagi muncul di dropdown baru)"))return;
  slsDB=slsDB.filter(s=>s.id!==id);
  persistSlsDB();
  renderDaftarSLS();
  renderDropdownSLS()
}
function bukaSettingSLS(){
  const modal=document.getElementById("modalSLS");
  if(modal){modal.style.display="flex";renderDaftarSLS()}
}
function tutupSettingSLS(){
  const modal=document.getElementById("modalSLS");
  if(modal)modal.style.display="none"
}
document.addEventListener("DOMContentLoaded",()=>{try{renderDropdownSLS()}catch(a){}});

// ===== SINKRONISASI DATA ANTAR PERANGKAT (lewat Apps Script + Drive) =====
// window.APPS_SCRIPT_URL diisi oleh lock.min.js (dimuat setelah file ini).
let _syncTimer = null;
let _syncInProgress = false;

function _getKodeDeviceAktif(){
  const kode = localStorage.getItem("se2026_kode_aktif_v1") || "";
  const device = localStorage.getItem("se2026_device_uuid_v1") || "";
  return { kode, device };
}

// Dipanggil tiap ada perubahan data (simpan responden, hapus, dsb).
// Di-debounce 4 detik supaya tidak spam server saat user ngetik cepat.
function jadwalkanSyncData(){
  if(_syncTimer) clearTimeout(_syncTimer);
  _syncTimer = setTimeout(()=>{ pushDataSinkron().catch(()=>{}); }, 4000);
}

async function pushDataSinkron(){
  if(_syncInProgress) return;
  const { kode, device } = _getKodeDeviceAktif();
  if(!kode || !device) return; // belum login
  if(!navigator.onLine) return;
  if(typeof window.APPS_SCRIPT_URL !== "string" || !window.APPS_SCRIPT_URL) return;

  _syncInProgress = true;
  try{
    const payload = {
      _meta:{app:"Asisten Petugas SE2026", exportedAt:(new Date).toISOString(), version:2},
      respondenDB: respondenDB,
      riwayat: riwayat,
      slsDB: slsDB
    };
    const body = JSON.stringify({ action:"upload", kode, device, data: JSON.stringify(payload) });
    const res = await fetch(window.APPS_SCRIPT_URL, {
      method:"POST",
      headers:{ "Content-Type":"text/plain;charset=utf-8" },
      body
    });
    const data = await res.json();
    if(data && data.success){
      localStorage.setItem("se2026_lastSyncAt", (new Date).toISOString());
    }
  }catch(e){
    // gagal sync (offline/timeout) -> biarkan, akan dicoba lagi di perubahan berikutnya
  }finally{
    _syncInProgress = false;
  }
}

// Dipanggil oleh lock.min.js sesaat setelah login berhasil, untuk menarik
// data yang pernah disinkronkan dari perangkat lain dan menggabungkannya
// dengan data lokal (data lokal tidak pernah ditimpa/dihapus, hanya digabung).
async function tarikDataSinkron(kode, device){
  if(!kode || !device) return;
  if(typeof window.APPS_SCRIPT_URL !== "string" || !window.APPS_SCRIPT_URL) return;
  try{
    const url = window.APPS_SCRIPT_URL + "?action=download&kode=" + encodeURIComponent(kode) + "&device=" + encodeURIComponent(device);
    const res = await fetch(url);
    const data = await res.json();
    if(!data || !data.success || !data.data) return; // belum ada data tersinkron -> normal untuk device baru

    const parsed = JSON.parse(data.data);
    let jumlahProfilBaru = 0, jumlahRiwayatBaru = 0, jumlahSlsBaru = 0;

    if(parsed.respondenDB){
      Object.keys(parsed.respondenDB).forEach(k=>{
        if(!respondenDB[k]){ respondenDB[k] = parsed.respondenDB[k]; jumlahProfilBaru++ }
      });
    }
    if(Array.isArray(parsed.riwayat)){
      const existingIds = new Set(riwayat.map(r=>r.id));
      parsed.riwayat.forEach(r=>{ if(!existingIds.has(r.id)){ riwayat.push(r); jumlahRiwayatBaru++ } });
    }
    if(Array.isArray(parsed.slsDB)){
      parsed.slsDB.forEach(sVal=>{
        if(sVal && sVal.nama && !slsDB.some(x=>x.id===sVal.id || x.nama.toLowerCase()===sVal.nama.toLowerCase())){
          slsDB.push({id:sVal.id||("sls_"+Date.now()+Math.random().toString(36).slice(2,6)), nama:sVal.nama});
          jumlahSlsBaru++;
        }
      });
    }

    if(jumlahProfilBaru || jumlahRiwayatBaru || jumlahSlsBaru){
      localStorage.setItem("se2026_respondenDB", JSON.stringify(respondenDB));
      localStorage.setItem("se2026_riwayat", JSON.stringify(riwayat));
      if(jumlahSlsBaru) localStorage.setItem("se2026_slsDB", JSON.stringify(slsDB));
      try{ renderRiwayat() }catch(e){}
      try{ renderDropdownSLS() }catch(e){}
      try{ renderRespondenAktifBar() }catch(e){}
      if(typeof showToast === "function") showToast(`🔄 Sinkron: ${jumlahProfilBaru} profil, ${jumlahRiwayatBaru} riwayat dimuat dari perangkat lain`);
    }
  }catch(e){
    // gagal tarik data (offline/timeout) -> app tetap jalan pakai data lokal
  }
}

window.pushDataSinkron = pushDataSinkron;
window.tarikDataSinkron = tarikDataSinkron;
window.jadwalkanSyncData = jadwalkanSyncData;
